code = """import json

civic_docs = locals().get('var_functions.query_db:18')
funding_data = locals().get('var_functions.query_db:19')

print('Civic docs type:', type(civic_docs))
print('Funding data type:', type(funding_data))

if isinstance(civic_docs, str) and civic_docs.endswith('.json'):
    with open(civic_docs, 'r') as f:
        civic_docs = json.load(f)

if isinstance(funding_data, str) and funding_data.endswith('.json'):
    with open(funding_data, 'r') as f:
        funding_data = json.load(f)

print('Loaded %d civic documents and %d funding records' % (len(civic_docs), len(funding_data)))

fema_emergency_projects = []
for fund in funding_data:
    project_name = fund.get('Project_Name', '')
    if any(keyword in project_name.upper() for keyword in ['FEMA', 'EMERGENCY', 'WARNING']):
        fema_emergency_projects.append({
            'Project_Name': project_name,
            'Funding_Source': fund.get('Funding_Source', 'Unknown'),
            'Amount': fund.get('Amount', 0),
            'Status': 'Unknown',
            'Topic': 'emergency, FEMA, warning',
            'Type': 'disaster'
        })

print('Found %d FEMA/emergency projects' % len(fema_emergency_projects))

result_json = json.dumps(fema_emergency_projects)
print('__RESULT__:')
print(result_json)"""

